import{_ as e,o as t,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"32. Salary Packaging","description":"","frontmatter":{"title":"32. Salary Packaging","eba":"Health Allied & Managers Admin 2021-2025","topics":["wages","salary-packaging","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/wages/32-salary-packaging.md","filePath":"ebas/has-managers-admin/common-terms/wages/32-salary-packaging.md"}'),o={name:"ebas/has-managers-admin/common-terms/wages/32-salary-packaging.md"};function r(i,a,l,c,g,p){return t(),n("div",null,[...a[0]||(a[0]=[s('<h1 id="_32-salary-packaging" tabindex="-1">32. Salary Packaging <a class="header-anchor" href="#_32-salary-packaging" aria-label="Permalink to &quot;32. Salary Packaging&quot;">​</a></h1><p><strong>32.1</strong> All Employees covered by this Agreement will have access to salary packaging arrangements as follows:</p><p><strong>(a)</strong> By agreement with the Employer, the current rate of pay and any monetary entitlements payable to the Employee as adjusted by the Agreement, may be salary packaged in accordance with the individual Health Service policy on salary packaging.</p><p><strong>(b)</strong> The Employee will compensate the Employer from his or her rate of pay for any FBT incurred as a consequence of any salary packaging arrangement the Employee has entered into. Where the Employee chooses not to pay any of the costs associated with their salary packaging, the Employer may cease the Employee’s salary packaging arrangements.</p><p><strong>(c)</strong> The parties agree that in the event that salary packaging ceases to be an advantage to the Employee (including as a result of subsequent changes to FBT legislation) the Employee may elect to convert the amount packaged to salary. Any costs associated with the conversion to salary will be borne by the Employee and the Employer will not be liable to make up any benefit lost as a consequence of an Employee’s decision to convert to salary.</p><p><strong>(d)</strong> The Employee will be responsible for all costs associated with the administration of their salary packaging arrangements, provided that such costs will be confined to reasonable commercial charges levied directly by the external salary packaging provider and/or in-house payroll services (as applicable), as varied from time to time.</p><p><strong>32.2</strong> The parties recommend to Employees who are considering salary packaging that they seek independent financial advice. The Employer will not be held be held responsible in any way for the cost or outcome of any such advice and furthermore, the parties agree that the Employee will pay for any costs associated with salary packaging.</p><p>Plain language terms: salary sacrifice, packaging, novated lease.</p>',8)])])}const h=e(o,[["render",r]]);export{m as __pageData,h as default};
